mapper.select:
select
    alarm_type as alarmType,
    count(*) as totalCount,
    count(case when alarm_status = 0 then 1 end) as activeCount,
    count(case when alarm_status = 1 then 1 end) as resolvedCount,
    count(case when deal_status = 0 then 1 end) as pendingCount,
    count(case when deal_status = 1 then 1 end) as completedCount
from (
    select alarm_type, 0 as alarm_status, 0 as deal_status
    from t_data_out_warn


            and out_put_id in

                #{outPutId}



            and start_time between #{req.beginTime} and #{req.endTime}


            and out_put_type = #{req.outPutType}


            and alarm_type = #{req.alarmType}


    union all
    select alarm_type, alarm_status, deal_status
    from t_data_out_alarm


            and out_put_id in

                #{outPutId}



            and start_time between #{req.beginTime} and #{req.endTime}


            and out_put_type = #{req.outPutType}


            and alarm_type = #{req.alarmType}


            and alarm_status = #{req.alarmStatus}


            and deal_status = #{req.dealStatus}


) t
group by alarm_type

select alarm_id, out_put_id, pollutant_code, data_type, alarm_type, start_time, null as end_time, 0 as alarm_status, 0 as deal_status, alarm_msg
from t_data_out_warn


        and out_put_id in

            #{outPutId}



        and start_time between #{req.beginTime} and #{req.endTime}


        and alarm_type = #{req.alarmType}


union all
select alarm_id, out_put_id, pollutant_code, data_type, alarm_type, start_time, end_time, alarm_status, deal_status, alarm_msg
from t_data_out_alarm


        and out_put_id in

            #{outPutId}



        and start_time between #{req.beginTime} and #{req.endTime}


        and alarm_type = #{req.alarmType}


        and alarm_status = #{req.alarmStatus}


        and deal_status = #{req.dealStatus}


order by alarm_id desc

mapper.update:
update t_data_out_alarm
set deal_status = #{dealStatus}
where alarm_id = #{alarmId}
